// Each parameter has a type annotation after the colon
function greet(name: string, age: number): void {
  console.log(name + ' is ' + age);
}

// : number after the parens declares the return type
function add(a: number, b: number): number {
  return a + b;  // must return a number
}

const sum = add(3, 4); // sum is inferred as number

// Arrow functions with expression body have implicit return
const double = (x: number): number => x * 2;

// With braces you need an explicit return statement
const triple = (x: number): number => {
  return x * 3;
};

// Optional params (? ) must come after required ones
function logMessage(msg: string, level?: string): void {
  const prefix = level ?? 'INFO'; // ?? provides fallback
  console.log('[' + prefix + '] ' + msg);
}

logMessage('Hello');        // level is undefined, defaults to 'INFO'

// Default values make the parameter implicitly optional
function createUser(name: string, isAdmin: boolean = false) {
  return { name, isAdmin };
}

createUser('Alice');       // isAdmin defaults to false
createUser('Bob', true);   // isAdmin is explicitly true

// ...nums gathers all extra arguments into an array
function sum(...nums: number[]): number {
  return nums.reduce((total, n) => total + n, 0);
}

const total = sum(1, 2, 3, 4); // total is 10
